import{_ as e,c as d,m as t,a as r,t as C,a5 as o,o as i}from"./chunks/framework.DwbewbAn.js";const u=JSON.parse('{"title":"C 发展史","description":"","frontmatter":{"title":"C 发展史"},"headers":[],"relativePath":"doc/编程语言/后端/C/发展史.md","filePath":"packages/doc/src/编程语言/后端/C/发展史.md","lastUpdated":1711551906000}'),n={name:"doc/编程语言/后端/C/发展史.md"},s={id:"frontmatter-title",tabindex:"-1"},c=t("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),l=o('<h2 id="c语言标准的发展阶段" tabindex="-1">C语言标准的发展阶段 <a class="header-anchor" href="#c语言标准的发展阶段" aria-label="Permalink to &quot;C语言标准的发展阶段&quot;">​</a></h2><table><thead><tr><th>年份</th><th>C标准</th><th>名称</th></tr></thead><tbody><tr><td>1978</td><td>K&amp;R C</td><td>K&amp;R C</td></tr><tr><td>1989</td><td>ISO C /ANSI C</td><td>C89/C90</td></tr><tr><td>1999</td><td>ISO/IEC 9899:1999</td><td>C99</td></tr><tr><td>2011</td><td>ISO/IEC 9899:2011</td><td>C11</td></tr><tr><td>2018</td><td>ISO/IEC 9899:2018</td><td>C18</td></tr><tr><td>2022</td><td>Yet to be determined</td><td>C2x</td></tr></tbody></table><h2 id="c语言标准介绍" tabindex="-1">C语言标准介绍 <a class="header-anchor" href="#c语言标准介绍" aria-label="Permalink to &quot;C语言标准介绍&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>K&amp;R C 1978年，丹尼斯·里奇(Dennis Ritchie)和布莱恩·科尔尼干(Brian Kernighan)出版了一本书，名叫《The C Programming Language》。这本书被C语言开发者们称为“K&amp;R”，很多年来被当作C语言的非正式的标准说明。人们称这个版本的C语言为“K&amp;R C”。</p><p>C89 为统一C语言版本，1983年美国国家标准局（American National Standards Institute，简称ANSI）成立了一个委员会，来制定C语言标准。1989年C语言标准被批准，被称为ANSI X3.159-1989 “Programming Language C”。这个版本的C语言标准通常被称为ANSI C。又由于这个版本是 89年完成制定的，因此也被称为C89。</p><p>C90 后来ANSI把这个标准提交到ISO（国际化标准组织），1990年被ISO采纳为国际标准，称为ISO C。又因为这个版本是1990年发布的，因此也被称为C90。所以ANSI C、ISO C、C89、C90这4个标准的内容其实是一样的。</p><p>C99 在ANSI C标准确立之后，C语言的规范在很长一段时间内都没有大的变动。1995年C程序设计语言工作组对C语言进行了一些修改，成为后来的1999年发布的ISO/IEC9899:1999标准，通常被成为C99。但是各个公司对C99的支持所表现出来的兴趣不同。当GCC和其它一些商业编译器支持C99的大部分特性的时候，微软和Borland却似乎对此不感兴趣。</p><p>C11 在2011年12月，ANSI采纳了ISO/IEC 9899:2011标准，这个标准通常即C11。</p><p>C18 2018年6月发布的ISO/IEC 9899:2018标准，这个标准被称为C18，是目前最新的C语言编程标准，该标准主要是对C11进行了补充和修正，并没有引入新的语言特性。</p><p>C2x 下一个版本的C语言标准，预计将于2022年12月1日完成/</p></div>',4);function p(a,h,_,m,I,S){return i(),d("div",null,[t("h1",s,[r(C(a.$frontmatter.title)+" ",1),c]),l])}const N=e(n,[["render",p]]);export{u as __pageData,N as default};
